    let downgrade_to_idle = match state {
        State::Idle => false,

        State::Focused { tab } => {
            let still_present = ctx.tabs.iter().any(|key| key == tab);

            let still_enabled = !ctx.disabled_tabs.contains(tab);

            !(still_present && still_enabled)
