+    let index = enabled.iter().position(|item| item == current).unwrap_or(0);
+
+    let next_index = match step {
+        FocusStep::Next => (index + 1) % len,
+        FocusStep::Prev => {
+            if index == 0 {
+                len - 1
+            } else {
+                index - 1
+            }
+        }
+    };
